839:     /**
840:      * We can retry a send if the error is transient and the number of attempts taken is fewer than the maximum allowed.
841:      * We can also retry OutOfOrderSequence exceptions for future batches, since if the first batch has failed, the
842:      * future batches are certain to fail with an OutOfOrderSequence exception.
843:      */
844:     private boolean canRetry(ProducerBatch batch, ProduceResponse.PartitionResponse response, long now) {
845:         return !batch.hasReachedDeliveryTimeout(accumulator.getDeliveryTimeoutMs(), now) &&
846:             batch.attempts() < this.retries &&
847:             !batch.isDone() &&
848:             (transactionManager == null ?
849:                     response.error.exception() instanceof RetriableException :
850:                     transactionManager.canRetry(response, batch));
851:     }
