601:     private void doSend(ClientRequest clientRequest, boolean isInternalRequest, long now, AbstractRequest request) {
602:         String destination = clientRequest.destination();
603:         RequestHeader header = clientRequest.makeHeader(request.version());
604:         if (log.isDebugEnabled()) {
605:             log.debug("Sending {} request with header {} and timeout {} to node {}: {}",
606:                 clientRequest.apiKey(), header, clientRequest.requestTimeoutMs(), destination, request);
607:         }
608:         Send send = request.toSend(header);
609:         InFlightRequest inFlightRequest = new InFlightRequest(
610:                 clientRequest,
611:                 header,
612:                 isInternalRequest,
613:                 request,
614:                 send,
615:                 now);
616:         this.inFlightRequests.add(inFlightRequest);
617:         selector.send(new NetworkSend(clientRequest.destination(), send));
618:     }
